            val newCost = cost + grid(i)(j + 1)
            if (newCost < dist(i)(j + 1)) {
                dist(i)(j + 1) = newCost
                pq.enqueue((newCost, (i, j + 1)))
            }
        }
        if (i + 1 < m) {
            val newCost = cost + grid(i + 1)(j)
            if (newCost < dist(i + 1)(j)) {
                dist(i + 1)(j) = newCost
                pq.enqueue((newCost, (i + 1, j)))
            }
        }

        // Teleportation: find all cells with value <= current cell's value
